var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"허억…… 허억……","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"끄, 끝났나?","JPN":"お、終わった？","ENG":"I-is it over?","TWN":"成…成功了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 미나 양. 등대는 완전히 파괴되었어요.","JPN":"はい、ミナさん。灯台を完全に壊したようです。","ENG":"Yes, Mina. We destroyed the Lighthouse.","TWN":"對，米娜，燈塔已經完全破壞掉了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"받으세요. 등대에 부착되어 있던 물건입니다.","JPN":"どうぞ。灯台に接続されていた物です。","ENG":"Take it. It was attached to the Lighthouse.","TWN":"這你收著，是裝在燈塔裡的東西。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 이게 메이슨 씨 일행이 찾고 있던 노바급 리액터겠죠.","JPN":"おそらくこれがメイソンさんたちの探していたノヴァ級リアクターでしょう。","ENG":"This must be the Nova-Class Reactor that Mr. Mason was looking for.","TWN":"應該就是梅森他們在找的諾瓦反應爐。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이제는 모든 에너지를 소모하고 텅 비어 버린 껍데기일 뿐이지만요.","JPN":"今はすべてのエネルギーを使い果たし、空っぽになってしまいましたけどね。","ENG":"It’s an empty shell now, though. All its energy is gone.","TWN":"不過裡面的能源應該都已經耗盡，只剩下空殼而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐! 코핀 컴퍼니 친구들!","JPN":"おい！　コフィンカンパニーさんよ！","ENG":"Hey, Coffin Company!","TWN":"喂！科芬公司的朋友們！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"괜찮으면 이쪽으로 와서 좀 도와 줘! 제이나의 상처가 심해!","JPN":"余裕あるならこっちに来て手を貸してくれ！　ジェイナの傷がひどい！","ENG":"Come and help me! Jaina is seriously hurt!","TWN":"你們可以過來幫我一下嗎！婕娜傷得很重！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알았어.","JPN":"わ、わかった。","ENG":"O-okay.","TWN":"喔，好！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아 참, 그런데 그 번개 대령님은?","JPN":"あ、ところであの稲妻大佐は？","ENG":"By the way, what happened to the lightning, Colonel?","TWN":"對了，那個閃電上校呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대령님!","JPN":"大佐！","ENG":"Colonel!","TWN":"上校！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이쪽도 위독해, 아저씨! 전신이 다 타 들어갔어!","JPN":"こっちも危ない状態なの、おじさん！　全身が燃やされてる！","ENG":"He’s not good! He’s burned to a crisp!","TWN":"大叔！這裡也很不妙！根本是全身燒傷！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"샬롯! 네가 대령님을 이렇게 만든 거야?!","JPN":"シャーロット！　あなたが大佐をこんな目に合わせたの！？","ENG":"Carlota! You did this to him?","TWN":"夏洛特！是你把上校弄成這樣的嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 이런 일을 벌이는 이유가 뭐야!","JPN":"こんなことをする理由は何！？","ENG":"Why are you doing this?","TWN":"你到底為什麼要這麼做！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"미안해, 늑대. 아니, 유미나.","JPN":"すまない、狼。いや、ヤナギ・ミナ。","ENG":"I’m sorry, Wolf. I mean, Yoo Mina.","TWN":"對不起，狼…不，是劉米娜。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"난 그저 내가 원하는 것을 얻기 위해 싸웠을 뿐이야.","JPN":"私はただ自分が望むものを得るために戦っただけだ。","ENG":"All I did was to fight for what I wanted.","TWN":"我不過是為想要的東西而戰。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"하늘을 봐. 이제 난 가문의 염원을 이룰 수 있어.","JPN":"空を見ろ。ようやく一族の悲願を叶えることができる。","ENG":"Look at the sky. Now my family will rise again.","TWN":"你看天空，我終於可以達成家族的期待！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하늘? 하늘에 뭐가……?","JPN":"空？　空に何が……？","ENG":"The sky? What’s in the sky?","TWN":"天空？天空怎樣……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":" 크윽!!","JPN":"くっ！！","ENG":"Hngh!","TWN":"唔唔！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양!","JPN":"ミナさん！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_07"},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 뭐야! 이 압력은!! 갑자기 중력이 강해지기라도 했나?","JPN":"な、なんだ、この圧力は！？　急に重力が強くなったのか？","ENG":"What’s with this pressure? Is gravity going crazy?","TWN":"搞什麼！這股壓力是怎麼回事！！是重力變大嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아뇨, 이건 너무도…… 너무도 강력한…… 침식파가 유입되면서 현실의 법칙이 부서져 나가고 있는 겁니다!","JPN":"いいえ、これはあまりにも……あまりにも強力な……侵食波が\\n流入していることで、現実の法則が壊れ始めているんです！","ENG":"No... It’s the Corruption Ray... It’s so strong, and now it’s destroying the laws of the Normalside!","TWN":"不對，這感覺……就是非常強烈的……侵蝕波入侵的同時，現實世界的定律也正在崩潰！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"침식파라고? 하지만 4종 침식체와 마주쳤을 때도 이런 압력은 느끼지 못했어!","JPN":"侵食波だと？　第4種侵食体に出くわした時も\\nこんな圧力は感じなかったぞ！？","ENG":"The Corruption Ray? But even Category 4 C.O.s don’t have this kind of power!","TWN":"是侵蝕波嗎？可是和4類侵蝕體交手時，也沒有感受過這樣的壓力！"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저건…… 4종 따위가 아닙니다.","JPN":"あれは……第4種なんかではありません。","ENG":"That’s far beyond Category 4...","TWN":"應該……不是4類。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"샬롯 양이 등대를 통해 부르려고 했던 게……","JPN":"シャーロットさんが灯台を使って呼び寄せようとしたのは……","ENG":"I guess Carlota used the Lighthouse...","TWN":"夏洛特想藉由燈塔召喚的……"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저거였군요.","JPN":"あれだったんですね。","ENG":"... to summon that.","TWN":"就是那個！"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"등대는…… 파괴했잖아?","JPN":"灯台は……壊れたでしょ？","ENG":"But we destroyed the Lighthouse, didn’t we?","TWN":"燈塔……不是已經破壞掉了嗎？"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"맞아요. 하지만 너무 늦었거나……","JPN":"そうです。でも遅すぎたのか……","ENG":"Yes, we did. Either we were too late...","TWN":"是沒錯，或許是我們動作太慢……"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이미 이쪽 차원에 근접한 상황에서 등대 이상의 유인요소가 작용했을 겁니다.","JPN":"すでにこちらの次元に近づいている状況で\\n灯台以上の誘引要素が作用したのでしょう。","ENG":"Or something else lured it here when it came close enough to this dimension.","TWN":"或是在已經接近這個次元的情況下，燈塔上的媒介發揮作用。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"유인 요소?","JPN":"誘引要素？","ENG":"Something else lured it?","TWN":"媒介？"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 제 추측이지만 등대에 결합된 건 노바급 리액터뿐만이 아니었을 겁니다.","JPN":"はい。あくまで推測ですが、灯台に接続していたのは\\nノヴァ級リアクターだけではなかったのだと思います。","ENG":"Yes. It’s only a theory, but I think she installed something else in the Lighthouse, along with the Nova-Class Reactor.","TWN":"沒錯，雖然只是猜測，但我想裝在燈塔上的應該不只諾瓦反應爐。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양에게서 추출한 클리포트 인자 결정도 함께 결합되어 있었겠죠.","JPN":"ミナさんから抽出したクリフォト・ファクターの結晶も\\n一緒に接続していたのでしょう。","ENG":"Probably your crystallized Qliphoth Factor.","TWN":"從米娜身上取出的逆卡巴拉因子結晶，應該也有一起裝上。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 등대의 공격이 미나 양의 힘과 비슷한 성질을 띄고 있었던 거고요.","JPN":"だから灯台の攻撃がミナさんの力と似た性質を持っていたのです。","ENG":"That must be why the light from the Lighthouse was very similar to your power.","TWN":"所以燈塔的攻擊才會有類似米娜能力的性質。"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저 존재가 뭔지는 모르지만, 미나 양의 힘의 파장에 이끌려 다가온 거라면…….","JPN":"あの存在が何なのかはわかりませんが、\\nミナさんの力の波長に惹かれて近づいてきたのなら……","ENG":"I don’t know what that is, but if your power drew it here...","TWN":"雖然不清楚那是什麼，但如果是為米娜的力量而來……"},"stage":{"bg":"MAINSTREAM_808","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제가 막겠습니다! 다들 엎드려요!","JPN":"僕が止めます！　皆さん伏せてください！","ENG":"I will stop it, everyone, stay down!","TWN":"我會擋下來！全部趴下！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};